export function getSkinImageUrl(championId: string, skinNum: number): string {
  const n = championId.charAt(0).toUpperCase() + championId.slice(1);
  return `https://ddragon.leagueoflegends.com/cdn/img/champion/loading/${n}_${skinNum}.jpg`;
}

export function getSkinsForChampion(championId: string): SkinData[] {
  const key = championId.charAt(0).toUpperCase() + championId.slice(1);
  if (championSkinMap[key]) return championSkinMap[key];
  return [{ num: 0, name: "Klasik" }];
}